import{toEntry,toProject}from"../../util/input.js";import{relative}from"../../util/path.js";import{hasDependency}from"../../util/plugin.js";import{getActionDependencies}from"../github-actions/index.js";const title="GitHub Action",enablers=["@actions/core"],isEnabled=({dependencies:e})=>hasDependency(e,enablers),config=["action.{yml,yaml}"],isAssumeArtifact=e=>/^(dist|build)\//.test(e),resolveConfig=async(e,t)=>{const i=[],n=getActionDependencies(e,t);for(const e of new Set(n)){const n=relative(t.cwd,e);isAssumeArtifact(n)?i.push(toProject(`!${n}`)):i.push(toEntry(n))}return i},plugin={title:title,enablers:enablers,isEnabled:isEnabled,config:config,resolveConfig:resolveConfig};export default plugin;